def subarrays_with_exactly_k_distinct(nums, k):
    from collections import defaultdict
    def at_most(K):
        count = defaultdict(int)
        left = 0
        res = 0
        distinct = 0
        for right, x in enumerate(nums):
            if count[x] == 0:
                distinct += 1
            count[x] += 1
            while distinct > K:
                count[nums[left]] -= 1
                if count[nums[left]] == 0:
                    distinct -= 1
                left += 1
            res += right - left + 1
        return res
    return at_most(k) - at_most(k - 1)

